"""CVSS v3.1 base-score computation (stdlib only).

Implements the official FIRST v3.1 formula, including the v3.1 ``roundup``.
Anchor: ``CVSS:3.1/AV:N/AC:L/PR:N/UI:N/S:U/C:H/I:N/A:N`` must yield 7.5 (High).
"""

from __future__ import annotations

import math

from scanner.models import Severity

_AV = {"N": 0.85, "A": 0.62, "L": 0.55, "P": 0.20}
_AC = {"L": 0.77, "H": 0.44}
_UI = {"N": 0.85, "R": 0.62}
_CIA = {"H": 0.56, "L": 0.22, "N": 0.0}
_PR_UNCHANGED = {"N": 0.85, "L": 0.62, "H": 0.27}
_PR_CHANGED = {"N": 0.85, "L": 0.68, "H": 0.50}
_REQUIRED = ("AV", "AC", "PR", "UI", "S", "C", "I", "A")


class CvssError(ValueError):
    """Raised on a malformed or incomplete CVSS vector."""


def parse_vector(vector: str) -> dict:
    v = vector.strip()
    parts = v.split("/")
    if parts and parts[0].upper().startswith("CVSS:"):
        parts = parts[1:]  # drop the "CVSS:3.1" prefix token
    metrics: dict = {}
    for part in parts:
        if not part:
            continue
        if ":" not in part:
            raise CvssError(f"malformed metric segment: {part!r}")
        key, _, val = part.partition(":")
        metrics[key.strip().upper()] = val.strip().upper()
    missing = [m for m in _REQUIRED if m not in metrics]
    if missing:
        raise CvssError(f"missing CVSS base metrics: {','.join(missing)}")
    return metrics


def _roundup(value: float) -> float:
    """Official CVSS v3.1 roundup to one decimal place."""
    int_input = round(value * 100000)
    if int_input % 10000 == 0:
        return int_input / 100000.0
    return (math.floor(int_input / 10000) + 1) / 10.0


def base_score(vector: str) -> float:
    m = parse_vector(vector)
    scope = m["S"]
    if scope not in ("U", "C"):
        raise CvssError(f"invalid Scope: {scope!r}")
    try:
        av = _AV[m["AV"]]
        ac = _AC[m["AC"]]
        ui = _UI[m["UI"]]
        conf, integ, avail = _CIA[m["C"]], _CIA[m["I"]], _CIA[m["A"]]
        pr = (_PR_UNCHANGED if scope == "U" else _PR_CHANGED)[m["PR"]]
    except KeyError as exc:  # invalid metric value
        raise CvssError(f"invalid metric value: {exc}") from exc

    iss = 1 - (1 - conf) * (1 - integ) * (1 - avail)
    if scope == "U":
        impact = 6.42 * iss
    else:
        impact = 7.52 * (iss - 0.029) - 3.25 * (iss - 0.02) ** 15
    exploitability = 8.22 * av * ac * pr * ui

    if impact <= 0:
        return 0.0
    if scope == "U":
        return _roundup(min(impact + exploitability, 10))
    return _roundup(min(1.08 * (impact + exploitability), 10))


def severity_from_score(score: float) -> Severity:
    if score <= 0:
        return Severity.NONE
    if score < 4.0:
        return Severity.LOW
    if score < 7.0:
        return Severity.MEDIUM
    if score < 9.0:
        return Severity.HIGH
    return Severity.CRITICAL


def compute(vector: str) -> tuple:
    """Return ``(base_score, Severity)`` for a CVSS v3.1 vector string."""
    score = base_score(vector)
    return score, severity_from_score(score)

