"""Filesystem walk that yields scannable Python files, pruning skip dirs.

Directory pruning happens during ``os.walk`` (we mutate ``dirnames`` in place),
so we never descend into ``tests/``, ``examples/``, ``vendor/`` etc. This alone
removes the bulk of the legacy scanners' false positives (e.g. the test-fixture
PEM in ``tests/constants.py``).
"""

from __future__ import annotations

import os
from collections.abc import Iterator
from pathlib import Path

from scanner.suppression import (
    DEFAULT_SKIP_DIRS,
    SKIP_FILE_PREFIXES,
    SKIP_FILE_SUFFIXES,
)

_TEST_DIRS = {"tests", "test", "testing", "__tests__"}


def iter_python_files(
    root, *, include_tests: bool = False, extra_skip_dirs=()
) -> Iterator[Path]:
    root = Path(root)
    if root.is_file():
        if root.suffix == ".py":
            yield root
        return
    skip = set(DEFAULT_SKIP_DIRS) | {d.lower() for d in extra_skip_dirs}
    if include_tests:
        skip -= _TEST_DIRS
    for dirpath, dirnames, filenames in os.walk(root):
        dirnames[:] = [d for d in dirnames if d.lower() not in skip]
        for filename in filenames:
            if not filename.endswith(".py"):
                continue
            if not include_tests:
                low = filename.lower()
                if low.startswith(SKIP_FILE_PREFIXES) or low.endswith(SKIP_FILE_SUFFIXES):
                    continue
            yield Path(dirpath) / filename

