"""Rule registry with auto-discovery.

Adding a rule is: drop a module in ``scanner/rules/``, subclass ``Rule``, and
decorate the class with ``@register``. ``all_rules()`` imports every module in
this package and instantiates the selected rules.
"""

from __future__ import annotations

import importlib
import pkgutil

_REGISTRY: dict = {}


def register(cls):
    if not getattr(cls, "id", ""):
        raise ValueError(f"rule {cls!r} must define a non-empty id")
    if cls.id in _REGISTRY:
        raise ValueError(f"duplicate rule id: {cls.id}")
    _REGISTRY[cls.id] = cls
    return cls


def _discover() -> None:
    import scanner.rules as pkg

    for mod in pkgutil.iter_modules(pkg.__path__):
        if mod.name not in ("base", "__init__"):
            importlib.import_module(f"scanner.rules.{mod.name}")


def all_rules(select=None, skip=None) -> list:
    _discover()
    ids = set(_REGISTRY)
    if select:
        ids &= set(select)
    if skip:
        ids -= set(skip)
    return [_REGISTRY[rule_id]() for rule_id in sorted(ids)]


def registry_ids() -> list:
    _discover()
    return sorted(_REGISTRY)

