"""PY-SSL-001 — Insecure SSL context (certificate verification disabled).

Flags a bare ``ssl.SSLContext()`` (or ``ssl._create_unverified_context()``),
which defaults to ``verify_mode=CERT_NONE`` and ``check_hostname=False``. The
secure factory ``ssl.create_default_context()`` is never flagged. When the
context is bound to a variable and later hardened in the same function, the
finding is suppressed; inline use (e.g. ``ssl=ssl.SSLContext() if ... else None``)
cannot be hardened and is reported with high confidence.
"""

from __future__ import annotations

import ast
from collections.abc import Iterator

from scanner.context import FileContext
from scanner.models import Confidence, Finding
from scanner.rules import register
from scanner.rules.base import Rule

_INSECURE_CTORS = {("ssl", "SSLContext"), ("ssl", "_create_unverified_context")}
_INSECURE_CTOR_NAMES = {"SSLContext", "_create_unverified_context"}
_INSECURE_VERIFY_MODES = {"CERT_NONE"}


@register
class InsecureSSLContextRule(Rule):
    id = "PY-SSL-001"
    name = "Insecure SSL context (certificate verification disabled)"
    cvss_vector = "CVSS:3.1/AV:N/AC:L/PR:N/UI:N/S:U/C:H/I:N/A:N"
    confidence = Confidence.PROBABLE
    cwe = "CWE-295"
    remediation = (
        "Use ssl.create_default_context(), which verifies certificates and "
        "hostnames. If you must construct an SSLContext manually, set "
        "check_hostname=True and verify_mode=ssl.CERT_REQUIRED before use."
    )
    references = (
        "https://docs.python.org/3/library/ssl.html#ssl.create_default_context",
        "https://cwe.mitre.org/data/definitions/295.html",
    )

    def analyze(self, ctx: FileContext) -> Iterator[Finding]:
        for node in ast.walk(ctx.tree):
            if not (isinstance(node, ast.Call) and self._is_insecure_ctor(node.func)):
                continue
            if self._hardened_in_scope(node, ctx):
                continue
            inline = self._assignment_target(node) is None
            yield self.finding(
                ctx,
                node,
                message=(
                    "`ssl.SSLContext()` defaults to verify_mode=CERT_NONE and "
                    "check_hostname=False, disabling TLS certificate verification "
                    "(man-in-the-middle risk). Use ssl.create_default_context()."
                ),
                confidence=Confidence.CONFIRMED if inline else Confidence.PROBABLE,
            )

    @staticmethod
    def _is_insecure_ctor(func: ast.AST) -> bool:
        if isinstance(func, ast.Attribute) and isinstance(func.value, ast.Name):
            return (func.value.id, func.attr) in _INSECURE_CTORS
        if isinstance(func, ast.Name):
