"""Scope filtering: decide which findings are in the engagement's scope.

Out-of-scope always wins over in-scope. Paths are POSIX-normalized before
matching so Windows ``tests\\constants.py`` and ``tests/constants.py`` behave
identically. Config can come from a JSON file always, or YAML if PyYAML is
installed; with no config, sensible defaults exclude tests/docs/build files.
"""

from __future__ import annotations

import fnmatch
import json
from dataclasses import replace
from pathlib import Path

DEFAULT_IN_SCOPE = ["**"]
DEFAULT_OUT_OF_SCOPE = [
    "tests/**",
    "test/**",
    "docs/**",
    "examples/**",
    "**/__pycache__/**",
    "setup.py",
    "conftest.py",
]


def _load_config(path) -> dict:
    p = Path(path)
    text = p.read_text(encoding="utf-8")
    if p.suffix.lower() in (".yaml", ".yml"):
        try:
            import yaml
        except ModuleNotFoundError as exc:
            raise RuntimeError(
                "PyYAML is not installed; use a .json scope file or "
                "`pip install bbscan[report]`"
            ) from exc
        return yaml.safe_load(text) or {}
    return json.loads(text)


class ScopeFilter:
    def __init__(self, in_scope=None, out_of_scope=None, on_out_of_scope="suppress"):
        self.in_scope = list(in_scope) if in_scope else list(DEFAULT_IN_SCOPE)
        self.out_of_scope = list(out_of_scope) if out_of_scope else list(DEFAULT_OUT_OF_SCOPE)
        if on_out_of_scope not in ("suppress", "flag"):
            raise ValueError("on_out_of_scope must be 'suppress' or 'flag'")
        self.on_out_of_scope = on_out_of_scope

    @classmethod
    def default(cls) -> "ScopeFilter":
        return cls()

    @classmethod
    def from_file(cls, path) -> "ScopeFilter":
        cfg = _load_config(path)
        return cls(
            in_scope=cfg.get("in_scope"),
            out_of_scope=cfg.get("out_of_scope"),
            on_out_of_scope=cfg.get("on_out_of_scope", "suppress"),
        )

    @staticmethod
    def _match(relpath, patterns) -> bool:
        p = str(relpath).replace("\\", "/")
        return any(fnmatch.fnmatch(p, pat) for pat in patterns)

    def is_in_scope(self, relpath) -> bool:
        if self._match(relpath, self.out_of_scope):  # out-of-scope wins
            return False
        return self._match(relpath, self.in_scope)

    def apply(self, findings) -> list:
        """Suppress (drop) or flag (mark ``in_scope=False``) out-of-scope findings."""
        result = []
        for f in findings:
            if self.is_in_scope(f.file):
                result.append(f)
            elif self.on_out_of_scope == "flag":
                result.append(replace(f, in_scope=False))
        return result

