"""Report renderers. All consume a ``Report`` and return text."""

from __future__ import annotations

from pathlib import Path

from scanner.reporting.json_report import render_json
from scanner.reporting.markdown_report import render_markdown
from scanner.reporting.sarif_report import render_sarif

_RENDERERS = {
    "json": render_json,
    "markdown": render_markdown,
    "sarif": render_sarif,
}


def render(report, fmt: str, **kwargs) -> str:
    try:
        renderer = _RENDERERS[fmt]
    except KeyError:
        raise ValueError(f"unknown report format: {fmt!r}")
    if fmt == "markdown":
        return renderer(report, **kwargs)
    return renderer(report)


def write_report(report, fmt: str, path, **kwargs) -> Path:
    text = render(report, fmt, **kwargs)
    out = Path(path)
    out.parent.mkdir(parents=True, exist_ok=True)
    out.write_text(text, encoding="utf-8")
    return out

