"""SARIF 2.1.0 output for GitHub code scanning / CI ingestion."""

from __future__ import annotations

import json

_LEVEL = {
    "CRITICAL": "error",
    "HIGH": "error",
    "MEDIUM": "warning",
    "LOW": "note",
    "NONE": "note",
}


def render_sarif(report) -> str:
    rules: dict = {}
    results = []
    for f in report.findings:
        if f.rule_id not in rules:
            rule: dict = {"id": f.rule_id, "name": f.rule_id}
            if f.cwe:
                rule["properties"] = {"cwe": f.cwe}
            rules[f.rule_id] = rule
        results.append(
            {
                "ruleId": f.rule_id,
                "level": _LEVEL.get(f.severity.value, "warning"),
                "message": {"text": f.message},
                "locations": [
                    {
                        "physicalLocation": {
                            "artifactLocation": {"uri": f.file},
                            "region": {"startLine": f.line, "startColumn": max(f.col + 1, 1)},
                        }
                    }
                ],
                "properties": {
                    "cvssVector": f.cvss_vector,
                    "cvssScore": f.cvss_score,
                    "confidence": f.confidence.value,
                },
            }
        )
    doc = {
        "$schema": "https://json.schemastore.org/sarif-2.1.0.json",
        "version": "2.1.0",
        "runs": [
            {
                "tool": {
                    "driver": {
                        "name": "bbscan",
                        "version": report.tool_version,
                        "rules": list(rules.values()),
                    }
                },
                "results": results,
            }
        ],
    }
    return json.dumps(doc, indent=2) + "\n"

