"""Minimal GitHub API client (stdlib urllib).

Replaces the legacy unauthenticated, retry-less ``requests.get`` calls. Reads a
token from ``$GITHUB_TOKEN`` (never a flag), backs off on 403/429 honoring
``Retry-After`` / ``X-RateLimit-Reset``, and follows ``Link`` pagination.
"""

from __future__ import annotations

import json
import os
import time
import urllib.error
import urllib.request
from dataclasses import dataclass
from typing import Optional


class GitHubError(RuntimeError):
    pass


@dataclass
class Repo:
    full_name: str
    clone_url: str
    default_branch: str
    archived: bool
    language: Optional[str]


def _to_repo(d: dict) -> Repo:
    return Repo(
        full_name=d.get("full_name", ""),
        clone_url=d.get("clone_url", ""),
        default_branch=d.get("default_branch", "main"),
        archived=bool(d.get("archived", False)),
        language=d.get("language"),
    )


def _next_link(link_header) -> Optional[str]:
    """Extract the rel="next" URL from an RFC-5988 Link header."""
    if not link_header:
        return None
    for part in link_header.split(","):
        segments = part.split(";")
        if len(segments) < 2:
            continue
        url = segments[0].strip().strip("<>")
        if any(s.strip() == 'rel="next"' for s in segments[1:]):
            return url
    return None


class GitHubClient:
    def __init__(self, token=None, *, base_url="https://api.github.com", max_retries=5, sleeper=time.sleep):
        self.token = token or os.environ.get("GITHUB_TOKEN")
        self.base_url = base_url.rstrip("/")
        self.max_retries = max_retries
        self._sleep = sleeper

    def _headers(self) -> dict:
        headers = {"Accept": "application/vnd.github+json", "User-Agent": "bbscan"}
        if self.token:
            headers["Authorization"] = f"Bearer {self.token}"
        return headers

    def _backoff(self, headers, attempt) -> None:
        retry_after = headers.get("Retry-After")
        if retry_after and str(retry_after).isdigit():
            self._sleep(int(retry_after))
            return
        remaining = headers.get("X-RateLimit-Remaining")
        reset = headers.get("X-RateLimit-Reset")
        if remaining == "0" and reset and str(reset).isdigit():
            self._sleep(min(max(int(reset) - int(time.time()), 1), 300))
            return
        self._sleep(min(2 ** attempt, 30))

    def _get(self, url):
        attempt = 0
        while True:
            request = urllib.request.Request(url, headers=self._headers())
            try:
                with urllib.request.urlopen(request, timeout=30) as resp:
                    return json.loads(resp.read().decode("utf-8")), dict(resp.headers)
            except urllib.error.HTTPError as exc:
                if exc.code in (403, 429) and attempt < self.max_retries:
                    self._backoff(dict(exc.headers or {}), attempt)
                    attempt += 1
                    continue
                raise GitHubError(f"GitHub API {exc.code} for {url}") from exc
            except urllib.error.URLError as exc:
                if attempt < self.max_retries:
                    self._sleep(min(2 ** attempt, 30))
                    attempt += 1
                    continue
                raise GitHubError(f"network error for {url}: {exc}") from exc

    def get_repo(self, owner, name) -> Repo:
        data, _ = self._get(f"{self.base_url}/repos/{owner}/{name}")
        return _to_repo(data)

    def list_org_repos(self, org, *, per_page=100, include=(), exclude=()) -> list:
        url = f"{self.base_url}/orgs/{org}/repos?per_page={per_page}&sort=updated"
        repos = []
        while url:
            data, headers = self._get(url)
            repos.extend(_to_repo(d) for d in data)
            url = _next_link(headers.get("Link"))
        if include:
            repos = [r for r in repos if any(p in r.full_name for p in include)]
        if exclude:
            repos = [r for r in repos if not any(p in r.full_name for p in exclude)]
        return repos

