import pytest

from scanner.scope_feed import (
    ScopeFeedError,
    extract_github_repos,
    find_program,
    parse_scope,
)

DATA = [
    {
        "handle": "coinbase",
        "name": "Coinbase",
        "targets": {
            "in_scope": [
                {"asset_type": "URL", "asset_identifier": "https://github.com/coinbase/coinbase-advanced-py"},
                {"asset_type": "SOURCE_CODE", "asset_identifier": "https://github.com/coinbase/cb-mpc.git"},
                {"asset_type": "URL", "asset_identifier": "https://api.coinbase.com"},
                {"asset_type": "URL", "asset_identifier": "https://github.com/coinbase/coinbase-advanced-py"},
                {"asset_type": "URL", "asset_identifier": "https://github.com/coinbase/contracts/tree/main/src"},
            ],
            "out_of_scope": [
                {"asset_identifier": "https://github.com/coinbase/legacy-thing"}
            ],
        },
    },
    {"handle": "github", "name": "GitHub", "targets": {"in_scope": []}},
]


def test_find_program_is_case_insensitive():
    assert find_program(DATA, "Coinbase")["handle"] == "coinbase"
    assert find_program(DATA, "missing") is None


def test_extract_dedups_strips_git_and_subpaths():
    repos = extract_github_repos(DATA[0])
    assert repos == ["coinbase/coinbase-advanced-py", "coinbase/cb-mpc", "coinbase/contracts"]


def test_extract_ignores_non_github_and_out_of_scope():
    repos = extract_github_repos(DATA[0])
    assert "coinbase/legacy-thing" not in repos
    assert all(r.count("/") == 1 for r in repos)


def test_parse_scope_collects_assets():
    scope = parse_scope(DATA, "coinbase")
    assert scope.name == "Coinbase"
    assert "coinbase/cb-mpc" in scope.github_repos
    assert any("api.coinbase.com" in a for a in scope.in_scope_assets)
    assert any("legacy-thing" in a for a in scope.out_of_scope_assets)


def test_unknown_program_raises():
    with pytest.raises(ScopeFeedError):
        parse_scope(DATA, "unknown")

